// Pointwise (1x1) conv2d, stride=1, tiled-streaming contract.
//   IC=64, OC=256, IH=IW=56, OH=OW=56, MP=4.
//   channel_tile=32 -> IN_BEATS=2, OUT_BEATS=8 per pixel.
// Latency: IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6) = 2 + 64*262 = 16770.
module node_conv_204 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam integer IC           = 64;
    localparam integer OC           = 256;
    localparam integer OH           = 56;
    localparam integer OW           = 56;
    localparam integer K_TOTAL      = 64;
    localparam integer MP           = 4;
    localparam integer OC_PASSES    = 64;
    localparam integer CHANNEL_TILE = 32;
    localparam integer IN_BEATS     = 2;
    localparam integer OUT_BEATS    = 8;
    localparam integer TILE_BITS    = 256;
    localparam integer SCALE_MULT  = 27623;
    localparam integer SCALE_SHIFT = 21;
    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 22;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = 33;
    localparam integer SCALE_CONST_W = 16;
    localparam integer SCALED_W      = 49;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF    = 49'sd1 <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 = SCALE_ROUND_HALF - 49'sd1;
    (* rom_style = "block", ram_style = "block" *)
    reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_204_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_204_bias.hex",    biases);
    end
    reg signed [7:0] in_latch [0:IC-1];
    localparam [2:0] ST_LOAD=3'd0, ST_RUNNING=3'd1, ST_BIAS=3'd2, ST_SCALE=3'd3, ST_OUTPUT=3'd4, ST_EMIT=3'd5;
    reg [2:0] state;
    reg [1:0]  in_beat_idx;
    reg [3:0]  out_beat_idx;
    reg [12:0] active_emit_count;
    reg [6:0]  oc_group;
    reg [2:0]  lane_counter;
    reg [6:0]  k_counter;
    reg [5:0]  pixel_row;
    reg [5:0]  pixel_col;
    reg signed [7:0]        weight_q;
    reg signed [7:0]        in_q;
    reg signed [PROD_W-1:0] mul_q;
    reg [2:0]               mac_lane_q1, mac_lane_q2;
    reg                     mac_valid_q1, mac_valid_q2;
    reg                     mac_done_issuing;
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;
    reg [OC*8-1:0] out_pack;
    integer i; integer lane_i; integer goc;
    wire [15:0] weight_addr;
    assign weight_addr = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;
    always @(posedge clk) begin
        if (state == ST_LOAD && valid_in && ready_in) begin
            for (i = 0; i < CHANNEL_TILE; i = i + 1)
                in_latch[in_beat_idx * CHANNEL_TILE + i] <= data_in[i*8 +: 8];
        end
        if (state == ST_LOAD && valid_in && ready_in && in_beat_idx == IN_BEATS - 1) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1) acc[lane_i] <= {ACC_W{1'b0}};
        end else if (state == ST_OUTPUT && oc_group != (OC_PASSES - 1)) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1) acc[lane_i] <= {ACC_W{1'b0}};
        end else if (state == ST_RUNNING && mac_valid_q2) begin
            acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
        end
        if (state == ST_BIAS) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                biased[lane_i] <= acc[lane_i] + biases[oc_group * MP + lane_i];
        end
        if (state == ST_SCALE) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                scaled[lane_i] <= $signed(biased[lane_i]) * $signed(SCALE_MULT_CONST);
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state<=ST_LOAD; ready_in<=1'b1; valid_out<=1'b0; data_out<=256'd0;
            in_beat_idx<=0; out_beat_idx<=0; active_emit_count<=0;
            oc_group<=0; lane_counter<=0; k_counter<=0;
            pixel_row<=0; pixel_col<=0;
            mac_valid_q1<=1'b0; mac_valid_q2<=1'b0; mac_done_issuing<=1'b0;
            mac_lane_q1<=3'd0; mac_lane_q2<=3'd0;
            weight_q<=8'sd0; in_q<=8'sd0; mul_q<={PROD_W{1'b0}};
            out_pack<={(OC*8){1'b0}}; v_tmp<={SCALED_W{1'b0}};
        end else begin
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx<=0; ready_in<=1'b0;
                            oc_group<=0; lane_counter<=0; k_counter<=0;
                            mac_done_issuing<=1'b0; state<=ST_RUNNING;
                        end else in_beat_idx <= in_beat_idx + 1;
                    end
                end
                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q<=weights[weight_addr]; in_q<=in_latch[k_counter];
                        mac_lane_q1<=lane_counter; mac_valid_q1<=1'b1;
                        if (k_counter == K_TOTAL - 1) begin
                            k_counter<=0;
                            if (lane_counter == MP - 1) begin lane_counter<=0; mac_done_issuing<=1'b1; end
                            else lane_counter <= lane_counter + 1;
                        end else k_counter <= k_counter + 1;
                    end else mac_valid_q1 <= 1'b0;
                    mul_q<=weight_q*in_q; mac_lane_q2<=mac_lane_q1; mac_valid_q2<=mac_valid_q1;
                    if (mac_done_issuing && !mac_valid_q1 && !mac_valid_q2) begin
                        state<=ST_BIAS; mac_done_issuing<=1'b0;
                    end
                end
                ST_BIAS:  state <= ST_SCALE;
                ST_SCALE: state <= ST_OUTPUT;
                ST_OUTPUT: begin
                    for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1) begin
                        v_tmp = (scaled[lane_i] + (scaled[lane_i][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                        goc = oc_group * MP + lane_i;
                        out_pack[goc*8 +: 8] <= (v_tmp > 49'sd127) ? 8'sd127 : (v_tmp < -49'sd128) ? -8'sd128 : v_tmp[7:0];
                    end
                    if (oc_group == OC_PASSES - 1) begin
                        valid_out<=1'b1; data_out<=out_pack[0 +: TILE_BITS];
                        out_beat_idx<=4'd1; state<=ST_EMIT;
                    end else begin
                        oc_group<=oc_group+1; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=1'b0; state<=ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    valid_out <= 1'b1;
                    data_out  <= out_pack[out_beat_idx * TILE_BITS +: TILE_BITS];
                    if (out_beat_idx == OUT_BEATS - 1) begin
                        out_beat_idx <= 0;
                        if (active_emit_count == OH * OW - 1) begin
                            active_emit_count<=0; pixel_row<=0; pixel_col<=0;
                        end else begin
                            active_emit_count <= active_emit_count + 1;
                            if (pixel_col == OW - 1) begin pixel_col<=0; pixel_row<=pixel_row+1; end
                            else pixel_col <= pixel_col + 1;
                        end
                        ready_in<=1'b1; state<=ST_LOAD;
                    end else out_beat_idx <= out_beat_idx + 1;
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
